class Solution:
    def areSentencesSimilar(self, sentence1, sentence2):
        a = sentence1.split()
        b = sentence2.split()
        if len(a) > len(b):
            a, b = b, a
        # a is shorter; try every split of a into prefix(p) + suffix(s)
        m = len(a)
        n = len(b)
        for p in range(m + 1):
            s = m - p
            if a[:p] == b[:p] and a[m - s:] == b[n - s:]:
                return True
        return False

