class Solution:
    def areSentencesSimilar(self, sentence1, sentence2):
        a = sentence1.split()
        b = sentence2.split()
        if len(a) > len(b):
            a, b = b, a
        m, n = len(a), len(b)
        i = 0
        while i < m and a[i] == b[i]:
            i += 1
        j = 0
        while j < m - i and a[m - 1 - j] == b[n - 1 - j]:
            j += 1
        return i + j >= m

