var areSentencesSimilar = function(sentence1, sentence2) {
    let a = sentence1.split(' ');
    let b = sentence2.split(' ');
    if (a.length > b.length) { const t = a; a = b; b = t; }
    const m = a.length, n = b.length;
    let i = 0;
    while (i < m && a[i] === b[i]) i++;
    let j = 0;
    while (j < m - i && a[m - 1 - j] === b[n - 1 - j]) j++;
    return i + j >= m;
};
